import{_ as i,I as e,o as s,c as l,aq as p,J as t}from"./chunks/framework.kV0qpqqq.js";const f=JSON.parse('{"title":"账号篇","description":"","frontmatter":{},"headers":[],"relativePath":"Guides/astrobox/AstroboxV1账号篇.md","filePath":"Guides/astrobox/AstroboxV1账号篇.md","lastUpdated":1773512079000}'),n={name:"Guides/astrobox/AstroboxV1账号篇.md"};function h(c,a,d,b,m,_){const r=e("NolebaseGitContributors"),o=e("NolebaseGitChangelog");return s(),l("div",null,[a[0]||(a[0]=p('<h1 id="账号篇" tabindex="-1">账号篇 <a class="header-anchor" href="#账号篇" aria-label="Permalink to “账号篇”">​</a></h1><h2 id="🌟-q1-米坛账号无法登录" tabindex="-1">🌟 Q1：米坛账号无法登录？ <a class="header-anchor" href="#🌟-q1-米坛账号无法登录" aria-label="Permalink to “🌟 Q1：米坛账号无法登录？”">​</a></h2><p>首先请你检查网络状况，并多次尝试。建议首选使用米坛社区官方客户端进行登录，其次将你的默认浏览器设置为 Chrome 或 Microsoft Edge，别用系统自带浏览器，夸克和QQ浏览器之类的也最好别用</p><p><mark>以下问题在 1.0.2 版本中已修复</mark></p><p><s>根据群里反馈，登录不上米坛账号（astrobox内一直转圈）的原因是你的头像是默认头像，可以尝试在米坛上传一下头像</s></p><h2 id="🌟-q2-小米账号无法登录" tabindex="-1">🌟 Q2：小米账号无法登录？ <a class="header-anchor" href="#🌟-q2-小米账号无法登录" aria-label="Permalink to “🌟 Q2：小米账号无法登录？”">​</a></h2><p>你可以使用<mark>手机号 或 米ID 或 邮箱＋密码</mark>登录</p><p>如果外区无法使用手机号登录，请等待后续版本更新</p><p>如果登录一直转圈：可以尝试检查账号下是否有穿戴设备、更改密码等操作，如果依旧不行请带 log 与我们反馈</p><h2 id="q3-小米账号登录在两步验证无限循环" tabindex="-1">Q3：小米账号登录在两步验证无限循环？ <a class="header-anchor" href="#q3-小米账号登录在两步验证无限循环" aria-label="Permalink to “Q3：小米账号登录在两步验证无限循环？”">​</a></h2><p>如果你在用wifi，换成流量；否则换成wifi；实在不行过会儿再试</p><h3 id="关于小米账号登录" tabindex="-1">关于小米账号登录 <a class="header-anchor" href="#关于小米账号登录" aria-label="Permalink to “关于小米账号登录”">​</a></h3><p>AstroBox 部分功能涉及通过调用小米账号服务接口以访问资源或启用特定设备操作。在此过程中，用户提供的账号凭证信息（包括用户名、密码或授权票据等）将直接提交至小米官方服务器，以完成身份验证。</p><p>本软件不会在未经用户同意的情况下存储、记录或篡改用户凭证信息。然而：</p><ul><li><p>该传输行为的安全性完全依赖于小米服务器及其接口实现机制，非本软件所能控制或担保</p></li><li><p>若因接口变化、服务策略调整或安全机制触发而导致用户账号受到限制、登录失败或产生数据问题，本软件及其开发者不承担相关责任；</p></li><li><p>用户应审慎判断是否使用此类功能，并对涉及账号凭证的使用风险承担全部责任。</p></li></ul><p>我们强烈建议用户仅在可信网络环境中操作，并在授权登录前评估其账号安全性要求。</p><p>此部分有关小米账号登录获取 Authkey 的代码已全部开源，有质疑请自行查看：</p><p><a href="https://github.com/AstralSightStudios/AstroBox-Public/blob/main/src-tauri/src/auth.rs" target="_blank" rel="noreferrer">https://github.com/AstralSightStudios/AstroBox-Public/blob/main/src-tauri/src/auth.rs</a></p><p>:::note</p><p>本教程由Yulimfish，川.，wuhaiqi等人编写，本人（lladlam）仅为第三方转载，著作权归Yulimfish，川.，wuhaiqi等人所有</p><p>:::</p>',21)),t(r),t(o)])}const x=i(n,[["render",h]]);export{f as __pageData,x as default};
